CREATE TABLE users (
  id INT PRIMARY KEY AUTO_INCREMENT,
  name VARCHAR(100),
  email VARCHAR(100)
);

CREATE TABLE orders (
  id INT PRIMARY KEY AUTO_INCREMENT,
  user_id INT,
  total DECIMAL(10,2),
  FOREIGN KEY (user_id) REFERENCES users(id)
);

-- DDL
CREATE TABLE users (id INT, name VARCHAR(100));

-- DML
INSERT INTO users VALUES (1, 'Alice');

-- DQL
SELECT * FROM users;

-- DCL
GRANT SELECT ON users TO 'john';

-- TCL
COMMIT;
